  ('elementary-7fec267e-moex-00686', 'elementary-7fec267e', 'elementary-7fec267e-moex-111-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '當法律規範有漏洞時，可以運用法律補充之方法使其完全。下列何者非屬法律補充之方法？', '["類推適用", "文義解釋", "目的限縮", "法律續造"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:01+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00687', 'elementary-7fec267e', 'elementary-7fec267e-moex-111-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '某法律規定：「本法自公布日施行。」若總統於民國110年6月1日公布該法，則該法應於何日生效？', '["6月1日", "6月2日", "6月3日", "6月4日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:01+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00688', 'elementary-7fec267e', 'elementary-7fec267e-moex-111-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '關於我國現行中央政府體制，下列敘述何者錯誤？', '["總統對行政院院長有人事任免權", "修憲後因立法院喪失對行政院院長的同意權，行政院不再對立法院負責", "總統享有被動的國會解散權", "我國中央政府體制既不是總統制，也不是內閣制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:01+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00689', 'elementary-7fec267e', 'elementary-7fec267e-moex-111-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '關於公法與私法之區別，下列敘述何者錯誤？', '["救濟之方式不同，公法適用行政爭訟，私法則適用民事訴訟", "強制執行之依據不同，公法適用行政執行法與行政訴訟法，私法適用強制執行法", "損害賠償管道不同，公法適用國家賠償法，私法適用民法", "勞動基準法之規範客體為私法上僱傭關係，故屬純粹的私法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:01+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00690', 'elementary-7fec267e', 'elementary-7fec267e-moex-111-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '下列何者非屬我國憲法或憲法增修條文賦予大法官之職權？', '["解釋憲法", "統一解釋法律及命令", "審理總統、副總統之罷免", "審理政黨違憲之解散"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:01+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00691', 'elementary-7fec267e', 'elementary-7fec267e-moex-111-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '關於刑法第19條第3項之規定，下列敘述何者錯誤？', '["學理上稱之為原因自由行為", "本項須行為人在實際實行犯罪時具備完全行為責任能力狀況", "現行立法模式，在學理上有稱為例外模式", "本項須行為人因故意或過失自行招致無責任能力或限制責任能力狀況"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:01+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00692', 'elementary-7fec267e', 'elementary-7fec267e-moex-111-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '下列何者是憲法最高性的直接展現？', '["行政院之施政不得牴觸立法院三讀通過，總統公布之法律", "法院之判決，不得不適用法規或適用不當", "立法院通過之法律，不得牴觸憲法", "行政機關之管轄權，不得違反其組織法規，非依法規不得設定或變更"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:01+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00693', 'elementary-7fec267e', 'elementary-7fec267e-moex-111-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '依司法院大法官解釋，有關自由民主憲政秩序，下列敘述何者錯誤？', '["係指憲法中具有本質之重要性而為規範秩序存立之基礎者", "憲法增修條文如與憲法中具有本質重要性之規範相衝突，依後法優於前法之原則，增修條文之效力優先", "其內涵包括憲法規定之民主共和國原則與國民主權原則", "凡憲法設置之機關，均有遵守自由民主憲政秩序之義務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:01+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL)
